// ── SHUFFLE ───────────────────────────────────────────────────────────────
const shuffle = (arr) => {
    const a = [...arr]
    for (let i = a.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [a[i], a[j]] = [a[j], a[i]]
    }
    return a
}

// ── PERSISTENT SHUFFLE QUEUE ──────────────────────────────────────────────
// Stores a shuffled index array in localStorage.
// Each game pops the next index — no repeats until all 464 exhausted,
// then reshuffles automatically.
const LS_KEY = 'hm_queue'

const getQueue = () => {
    try {
        const stored = JSON.parse(localStorage.getItem(LS_KEY))
        if (Array.isArray(stored) && stored.length > 0) return stored
    } catch {}
    return null
}

const saveQueue = (queue) => {
    localStorage.setItem(LS_KEY, JSON.stringify(queue))
}

const getNextFallback = () => {
    let queue = getQueue()
    if (!queue) {
        queue = shuffle([...Array(fallbackPuzzles.length).keys()])
        saveQueue(queue)
    }
    const index = queue.pop()
    saveQueue(queue)
    return fallbackPuzzles[index]
}

// ── GET PUZZLE ────────────────────────────────────────────────────────────
const getPuzzle = async (wordcount = 4) => {
    try {
        const response = await fetch(`/.netlify/functions/getPuzzle?wordCount=${wordCount}`)
        if (response.status === 200) {
            const data = await response.json()
            return data.puzzle
        }
        throw new Error('Bad response.')
    } catch (e) {
        console.warn('Puzzle API unavailable, using fallback.', e)
        return getNextFallback()
    }
}

export { getPuzzle as default }